1	const PROCESSING_FEE = 5;
2	const COMPONENT_BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_UNIT_PREMIUM = 25;
5	
6	const CURSE_SURCHARGE_RATE = 0.5;
7	const HIGH_ENCHANTMENT_RATE = 0.3;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	const FIRST_INSURANCE_RATE = 0.1;
10	const LOYALTY_DISCOUNT_RATE = 0.2;
11	const LOYALTY_THRESHOLD_YEARS = 2;
12	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: COMPONENT_UNIT_PREMIUM,
20	  moonstone: COMPONENT_UNIT_PREMIUM,
21	};
22	
23	const INSURANCE_VALUES: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	const DEDUCTIBLE = 100;
33	const CAP_MULTIPLIER = 2;
34	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
35	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
36	
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	
39	interface Item {
40	  type: string;
41	  material?: string;
42	  enchantment?: number;
43	  cursed?: boolean;
44	}
45	
46	interface QuoteStep {
47	  op: "quote";
48	  items: Item[];
49	}
50	
51	interface Damage {
52	  itemType: string;
53	  amount: number;
54	}
55	
56	interface ClaimStep {
57	  op: "claim";
58	  policy: number;
59	  incident: { cause?: string; damages: Damage[] };
60	}
61	
62	type Step = QuoteStep | ClaimStep;
63	
64	interface Scenario {
65	  customer: { yearsWithMHPCO: number };
66	  steps: Step[];
67	}
68	
69	interface PolicyState {
70	  items: Item[];
71	  insuranceSum: number;
72	  cap: number;
73	  remainingCap: number;
74	}
75	
76	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
77	const isMainItem = (item: Item): boolean => !isComponent(item);
78	
79	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
80	
81	const countsBy = <T>(items: T[], keyOf: (item: T) => string): Map<string, number> =>
82	  items.reduce((counts, item) => {
83	    const key = keyOf(item);
84	    counts.set(key, (counts.get(key) ?? 0) + 1);
85	    return counts;
86	  }, new Map<string, number>());
87	
88	const countsByType = (items: Item[]): Map<string, number> =>
89	  countsBy(items, (item) => item.type);
90	
91	const componentGroupPremium = (count: number): number =>
92	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_UNIT_PREMIUM;
93	
94	const sumComponentPremiums = (components: Item[]): number =>
95	  Array.from(countsByType(components).values()).reduce(
96	    (total, count) => total + componentGroupPremium(count),
97	    0,
98	  );
99	
100	const sumMainItemPremiums = (mainItems: Item[]): number =>
101	  mainItems.reduce((total, item) => total + basePremiumFor(item), 0);
102	
103	const policyBasePremium = (items: Item[]): number =>
104	  sumMainItemPremiums(items.filter(isMainItem)) +
105	  sumComponentPremiums(items.filter(isComponent));
106	
107	const curseRate = (item: Item): number => (item.cursed ? CURSE_SURCHARGE_RATE : 0);
108	
109	const highEnchantmentRate = (item: Item): number =>
110	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0;
111	
112	const itemModifierRate = (item: Item): number => curseRate(item) + highEnchantmentRate(item);
113	
114	const itemModifierSurcharge = (item: Item): number =>
115	  isComponent(item) ? 0 : basePremiumFor(item) * itemModifierRate(item);
116	
117	const sumItemModifiers = (items: Item[]): number =>
118	  items.reduce((total, item) => total + itemModifierSurcharge(item), 0);
119	
120	interface CustomerContext {
121	  yearsWithMHPCO: number;
122	  isFollowUpContract: boolean;
123	}
124	
125	const loyaltyDiscountRate = (ctx: CustomerContext): number =>
126	  ctx.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0;
127	
128	const followUpDiscountRate = (ctx: CustomerContext): number =>
129	  ctx.isFollowUpContract ? FOLLOW_UP_DISCOUNT_RATE : 0;
130	
131	const policyModifierRate = (ctx: CustomerContext): number =>
132	  FIRST_INSURANCE_RATE - loyaltyDiscountRate(ctx) - followUpDiscountRate(ctx);
133	
134	const policyModifierAmount = (policyBase: number, ctx: CustomerContext): number =>
135	  policyBase * policyModifierRate(ctx);
136	
137	const computeQuote = (step: QuoteStep, ctx: CustomerContext) => {
138	  const policyBase = policyBasePremium(step.items);
139	  const itemSurcharges = sumItemModifiers(step.items);
140	  const policyMods = policyModifierAmount(policyBase, ctx);
141	  const premium = policyBase + itemSurcharges + policyMods + PROCESSING_FEE;
142	  return { premium: Math.ceil(premium) };
143	};
144	
145	const insuranceSumOf = (items: Item[]): number =>
146	  items.reduce((total, item) => total + (INSURANCE_VALUES[item.type] ?? 0), 0);
147	
148	const createPolicy = (items: Item[]): PolicyState => {
149	  const insuranceSum = insuranceSumOf(items);
150	  const cap = insuranceSum * CAP_MULTIPLIER;
151	  return { items, insuranceSum, cap, remainingCap: cap };
152	};
153	
154	const hasHighClaimEnchantment = (item: Item | undefined): boolean =>
155	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
156	
157	const reimbursedAmount = (damage: Damage, item: Item | undefined): number =>
158	  hasHighClaimEnchantment(item) ? damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE : damage.amount;
159	
160	const damagePayout = (damage: Damage, item: Item | undefined): number =>
161	  Math.max(0, reimbursedAmount(damage, item) - DEDUCTIBLE);
162	
163	const findItem = (items: Item[], itemType: string): Item | undefined =>
164	  items.find((i) => i.type === itemType);
165	
166	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
167	  damages.reduce((total, damage) => total + damagePayout(damage, findItem(items, damage.itemType)), 0);
168	
169	const processClaim = (step: ClaimStep, policy: PolicyState) => {
170	  const uncappedPayout = sumDamagePayouts(step.incident.damages, policy.items);
171	  const payout = Math.min(uncappedPayout, policy.remainingCap);
172	  policy.remainingCap -= payout;
173	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
174	};
175	
176	interface ScenarioState {
177	  policies: PolicyState[];
178	  quoteCount: number;
179	  yearsWithMHPCO: number;
180	}
181	
182	const KNOWN_ITEM_TYPES = new Set(Object.keys(BASE_PREMIUMS));
183	
184	const isKnownItem = (item: Item): boolean => KNOWN_ITEM_TYPES.has(item.type);
185	
186	const assertAllValid = <T>(
187	  collection: T[],
188	  isValid: (element: T) => boolean,
189	  buildError: (invalid: T) => string,
190	): void => {
191	  const invalid = collection.find((element) => !isValid(element));
192	  if (invalid) {
193	    throw new Error(buildError(invalid));
194	  }
195	};
196	
197	const validateQuoteItems = (items: Item[]): void =>
198	  assertAllValid(items, isKnownItem, (item) => `Unknown item type: ${item.type}`);
199	
200	const handleQuoteStep = (step: QuoteStep, state: ScenarioState) => {
201	  validateQuoteItems(step.items);
202	  const ctx: CustomerContext = {
203	    yearsWithMHPCO: state.yearsWithMHPCO,
204	    isFollowUpContract: state.quoteCount > 0,
205	  };
206	  state.quoteCount += 1;
207	  state.policies.push(createPolicy(step.items));
208	  return computeQuote(step, ctx);
209	};
210	
211	const insuredTypesOf = (items: Item[]): Set<string> =>
212	  new Set(items.map((item) => item.type));
213	
214	const validateClaimDamages = (damages: Damage[], policyItems: Item[]): void => {
215	  assertAllValid(
216	    damages,
217	    (damage) => damage.amount >= 0,
218	    (damage) => `Negative damage amount: ${damage.amount}`,
219	  );
220	  const insuredTypes = insuredTypesOf(policyItems);
221	  assertAllValid(
222	    damages,
223	    (damage) => insuredTypes.has(damage.itemType),
224	    (damage) => `Damage references item not in policy: ${damage.itemType}`,
225	  );
226	  const insuredCounts = countsByType(policyItems);
227	  const damageCounts = countsBy(damages, (damage) => damage.itemType);
228	  assertAllValid(
229	    Array.from(damageCounts.entries()),
230	    ([itemType, count]) => count <= (insuredCounts.get(itemType) ?? 0),
231	    ([itemType]) => `Damage entries for ${itemType} exceed insured count`,
232	  );
233	};
234	
235	const handleClaimStep = (step: ClaimStep, state: ScenarioState) => {
236	  const policy = state.policies[step.policy];
237	  validateClaimDamages(step.incident.damages, policy.items);
238	  return processClaim(step, policy);
239	};
240	
241	export const runScenario = (input: unknown): unknown => {
242	  const scenario = input as Scenario;
243	  const state: ScenarioState = {
244	    policies: [],
245	    quoteCount: 0,
246	    yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
247	  };
248	  const results = scenario.steps.map((step) =>
249	    step.op === "quote" ? handleQuoteStep(step, state) : handleClaimStep(step, state),
250	  );
251	  return { results };
252	};
